        else:
            board.append([' ' if col % 2 != 0 else 'R' for col in range(8)])
    return board

def print_board(board):
    for row in board:
        print(' '.join(row))

def get_piece_color(board, x, y):
    return board[x][y]

def is_valid_move(board, start_x, start_y, end_x, end_y):
    piece = board[start_x][start_y]
    if piece == ' ':
        return False
    # Check for valid diagonal move
    if abs(end_x - start_x) != 1 or abs(end_y - start_y) != 1:
        return False
    # Check for opponent's piece to capture
    if (abs(end_x - start_x) == 2 and abs(end_y - start_y) == 2):
        mid_x = (start_x + end_x) // 2
        mid_y = (start_y + end_y) // 2
        if get_piece_color(board, mid_x, mid_y) in ['B', 'R']:
            board[mid_x][mid_y] = ' '
        else:
            return False
    # Check for valid direction of movement
    if piece == 'B' and end_y < start_y:
        return False
    elif piece == 'R' and end_y > start_y:
        return False
    return True

